commit 722d94847de29310e8aa03fcbdb41fc92c521756
Author: Jamie Hill-Daniel <jamie@hill-daniel.co.uk>
Date:   Tue Jan 18 08:06:04 2022 +0100

    vfs: fs_context: fix up param length parsing in legacy_parse_param

    The "PAGE_SIZE - 2 - size" calculation in legacy_parse_param() is an
    unsigned type so a large value of "size" results in a high positive
    value instead of a negative value as expected.  Fix this by getting rid
    of the subtraction.

    Signed-off-by: Jamie Hill-Daniel <jamie@hill-daniel.co.uk>
    Signed-off-by: William Liu <willsroot@protonmail.com>
    Tested-by: Salvatore Bonaccorso <carnil@debian.org>
    Tested-by: Thadeu Lima de Souza Cascardo <cascardo@canonical.com>
    Acked-by: Dan Carpenter <dan.carpenter@oracle.com>
    Acked-by: Al Viro <viro@zeniv.linux.org.uk>
    Signed-off-by: Greg Kroah-Hartman <gregkh@linuxfoundation.org>
    Signed-off-by: Linus Torvalds <torvalds@linux-foundation.org>

diff --git a/fs/fs_context.c b/fs/fs_context.c
index b7e43a780a62..24ce12f0db32 100644
--- a/fs/fs_context.c
+++ b/fs/fs_context.c
@@ -471,161 +471,161 @@ void put_fs_context(struct fs_context *fc)
 	security_free_mnt_opts(&fc->security);
 	put_net(fc->net_ns);
 	put_user_ns(fc->user_ns);
 	put_cred(fc->cred);
 	put_fc_log(fc);
 	put_filesystem(fc->fs_type);
 	kfree(fc->source);
 	kfree(fc);
 }
 EXPORT_SYMBOL(put_fs_context);

 /*
  * Free the config for a filesystem that doesn't support fs_context.
  */
 static void legacy_fs_context_free(struct fs_context *fc)
 {
 	struct legacy_fs_context *ctx = fc->fs_private;

 	if (ctx) {
 		if (ctx->param_type == LEGACY_FS_INDIVIDUAL_PARAMS)
 			kfree(ctx->legacy_data);
 		kfree(ctx);
 	}
 }

 /*
  * Duplicate a legacy config.
  */
 static int legacy_fs_context_dup(struct fs_context *fc, struct fs_context *src_fc)
 {
 	struct legacy_fs_context *ctx;
 	struct legacy_fs_context *src_ctx = src_fc->fs_private;

 	ctx = kmemdup(src_ctx, sizeof(*src_ctx), GFP_KERNEL);
 	if (!ctx)
 		return -ENOME

